examples.original_ir:
define <2 x i32> @test(<2 x i32> %x, <2 x i32> %y) {
  %cmp = icmp eq <2 x i32> %x, <i32 1, i32 undef>
  %sel = select <2 x i1> %cmp, <2 x i32> %x, <2 x i32> %y
  ret <2 x i32> %sel
}

